// LEVEL 1: Extract investment/listing URLs from NO search page
const items = $input.all();

function extractHtml(item) {
	if (item.binary?.data?.data) {
		return Buffer.from(item.binary.data.data, 'base64').toString('utf-8');
	}
	if (typeof item === 'string') {
		return item;
	}
	if (typeof item?.json === 'string') {
		return item.json;
	}
	if (item?.json?.data) {
		return item.json.data;
	}
	if (item?.data) {
		return item.data;
	}
	return JSON.stringify(item?.json || item || '');
}

function cleanText(value) {
	if (!value) return '';
	return String(value)
		.replace(/<[^>]+>/g, ' ')
		.replace(/&nbsp;|&#160;/g, ' ')
		.replace(/&amp;/g, '&')
		.replace(/&quot;/g, '"')
		.replace(/&#39;|&apos;/g, "'")
		.replace(/&sup2;/g, '²')
		.replace(/\s+/g, ' ')
		.trim();
}

function toAbsoluteUrl(rawUrl) {
	const value = String(rawUrl || '').trim();
	if (!value) return '';
	const absolute = value.startsWith('http')
		? value
		: `https://krakow.nieruchomosci-online.pl${value.startsWith('/') ? '' : '/'}${value}`;
	return absolute.split('?')[0].trim();
}

function isInvestmentUrl(url) {
	if (!url.includes('nieruchomosci-online.pl')) return false;
	if (!/\.html$/i.test(url)) return false;
	if (/\/szukaj\.html$/i.test(url)) return false;
	if (/\/(\d{7,10})\.html$/i.test(url)) return false;
	if (/\/dodaj\.html$/i.test(url)) return false;
	if (/\/oferta-dla-/i.test(url)) return false;
	return true;
}

function parseFromHrefFallback(html) {
	const results = [];
	const regex = /href="([^"]+\.html(?:\?[^\"]*)?)"/g;
	let match;

	while ((match = regex.exec(html)) !== null) {
		const url = toAbsoluteUrl(match[1]);
		if (!url || !isInvestmentUrl(url)) continue;

		const slug = (url.match(/\/([^\/]+)\.html$/i) || [])[1] || '';
		results.push({
			url,
			investment_name: cleanText(slug.replace(/-/g, ' ')),
			investment_id: slug,
		});
	}

	return results;
}

try {
	const allResults = [];

	for (const item of items) {
		const html = extractHtml(item);
		allResults.push(...parseFromHrefFallback(html));
	}

	const uniqueMap = new Map();
	for (const entry of allResults) {
		if (entry?.url) {
			uniqueMap.set(entry.url, entry);
		}
	}

	return Array.from(uniqueMap.values()).map((json) => ({ json }));
} catch (error) {
	return [{ json: { error: `Level 1 parsing error: ${error.message}` } }];
}

// LEVEL 2: Parse apartments from investment page JSON-LD
const crypto = require('crypto');

const items = $input.all();
const results = [];

function classifyOffer(offer) {
	return {
		...offer,
		geo_status: 'unknown',
		geo_confidence: 'low',
		geo_reason: 'Krakow detected but district is missing or unsupported.',
		policy_version: 'south-krakow-v1',
		is_exception_candidate: false,
		review_status: 'pending',
		is_soft_blocked: true,
		needs_manual_review: true,
		excluded_from_feedback_loop: true,
		is_in_trash: false,
	};
}

function extractHtml(item) {
	if (item.binary && item.binary.data) {
		return Buffer.from(item.binary.data.data, 'base64').toString('utf-8');
	}
	if (typeof item === 'string') {
		return item;
	}
	if (item && item.data) {
		return item.data;
	}
	if (typeof item.json === 'string') {
		return item.json;
	}
	if (item.json && item.json.data) {
		return item.json.data;
	}
	return JSON.stringify(item.json || item);
}

function cleanText(value) {
	if (!value) {
		return '';
	}
	return String(value)
		.replace(/<[^>]+>/g, ' ')
		.replace(/&nbsp;|&#160;/g, ' ')
		.replace(/&amp;/g, '&')
		.replace(/&quot;/g, '"')
		.replace(/&#39;|&apos;/g, "'")
		.replace(/&sup2;/g, '²')
		.replace(/\s+/g, ' ')
		.trim();
}

function toNumber(value) {
	if (typeof value === 'number') {
		return Number.isFinite(value) ? value : 0;
	}
	if (value === null || value === undefined || value === '') {
		return 0;
	}
	const normalized = String(value)
		.replace(/\u00a0/g, '')
		.replace(/\s+/g, '')
		.replace(',', '.')
		.replace(/[^\d.-]/g, '');
	const parsed = Number(normalized);
	return Number.isFinite(parsed) ? parsed : 0;
}

const MIN_AREA_SQM = 90;

function parseArea(value) {
	const text = cleanText(value);
	// Match "od 90 m²", "147,32 m²", "90.5 m2"
	const match = text.match(/(?:od\s*)?([\d][\d\s.,]*)\s*m(?:²|2)/i);
	return match ? toNumber(match[1]) : 0;
}

function calculateAreaFromPrice(totalPrice, pricePerM2) {
	const p = toNumber(totalPrice);
	const ppm = toNumber(pricePerM2);
	if (ppm > 0 && p > 0) {
		return Math.round((p / ppm) * 100) / 100;
	}
	return 0;
}

function stripQuery(url) {
	return String(url || '').split('?')[0].trim();
}

function buildDetailUrl(url) {
	return stripQuery(String(url || '')).trim();
}

function extractDistrict(locationText) {
	const location = cleanText(locationText);
	if (!location) {
		return 'Kraków';
	}
	const district = location.replace(/,\s*Krak[óo]w$/i, '').trim();
	return district || 'Kraków';
}

function findOfferList(node) {
	if (!node) {
		return [];
	}
	if (Array.isArray(node)) {
		const directOffers = node.filter((entry) => entry && entry['@type'] === 'Offer');
		if (directOffers.length > 0) {
			return directOffers;
		}
		for (const entry of node) {
			const nestedOffers = findOfferList(entry);
			if (nestedOffers.length > 0) {
				return nestedOffers;
			}
		}
		return [];
	}
	if (typeof node !== 'object') {
		return [];
	}
	for (const value of Object.values(node)) {
		const nestedOffers = findOfferList(value);
		if (nestedOffers.length > 0) {
			return nestedOffers;
		}
	}
	return [];
}

function parseJsonLdOffers(html) {
	const blocks = [];
	const regex = /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
	let match;

	while ((match = regex.exec(html)) !== null) {
		blocks.push(match[1]);
	}

	for (const block of blocks) {
		try {
			const parsed = JSON.parse(block.trim());
			const offers = findOfferList(parsed);

			if (offers.length > 0) {
				return offers;
			}
		} catch (error) {
		}
	}

	return [];
}

function buildExternalId(offer, url, index) {
	if (url) {
		const idMatch = String(url).match(/\/(\d+)\.html/);
		if (idMatch) return `NO-${idMatch[1]}`;
		return `NO-${crypto.createHash('md5').update(url).digest('hex')}`;
	}
	return `NO-${index + 1}`;
}

try {
	for (const item of items) {
		const html = extractHtml(item);
		const offers = parseJsonLdOffers(html);

		if (offers.length === 0) {
			continue;
		}

		for (let index = 0; index < offers.length; index += 1) {
			const offer = offers[index] || {};
			const baseUrl = stripQuery(offer.url || '');

			// Skip aggregate entries that don't point to an individual offer page
			if (offer.url && !String(offer.url).match(/\/\d+\.html/)) continue;

			const offerId = (baseUrl.match(/\/(\d+)\.html/) || [])[1] || (index + 1);

			const totalPrice = toNumber(offer.price);
			const pricePerM2 = toNumber(offer.priceSpecification && offer.priceSpecification.price);
			const nameArea = parseArea(offer.name);
			const area = nameArea > 0 ? nameArea : calculateAreaFromPrice(totalPrice, pricePerM2);

			// Skip offers below minimum area threshold
			if (area > 0 && area < MIN_AREA_SQM) continue;

			results.push(
				classifyOffer({
					external_id: buildExternalId(offer, baseUrl, index),
					url: buildDetailUrl(baseUrl),
					category: 'mieszkanie-krakow',
					title: cleanText(offer.name) || `Oferta NO: ${offerId}`,
					price: totalPrice,
					price_per_m2: pricePerM2,
					area: area,
					lot_size: 0,
					construction_year: 0,
					created_at: new Date().toISOString(),
					property_portal: 'Nieruchomości online',
					location_text: 'Kraków',
					district: 'Kraków',
					market_type: 'residential',
					source_offer_id: '',
				})
			);
		}
	}
} catch (error) {
	return [{ json: { error: `Level 2 parsing error: ${error.message}` } }];
}

const uniqueMap = new Map();
results.forEach((result) => uniqueMap.set(result.external_id, result));

return Array.from(uniqueMap.values()).map((json) => ({ json }));

return [{
  json: {
    "workflow_name": "Real Estate AI Agent",
    "workflow_version": "1.0.1",
    "workflow_display_name": "Real Estate AI Agent",
    "git_sha": "5a08417",
