const items = $input.all();
const html = items[0].json.data || "";

if (!html || html.length < 100) {
    return [{ json: { error: "No HTML content found" } }];
}

function extractText(html, regex) {
    const m = html.match(regex);
    return m ? m[1].trim() : "";
}

function parseNumber(str) {
    if (!str) return 0;
    const cleaned = str.replace(/\s/g, "").replace(",", ".");
    const n = parseFloat(cleaned);
    return isNaN(n) ? 0 : n;
}

function extractSpec(html, label) {
    const re = new RegExp(
        '<p class="spacificationLabel">[^<]*?' + label + '[^<]*?</p>\\s*<p class="spacificationValue">([\\s\\S]*?)</p>',
        "i"
    );
    const m = html.match(re);
    if (!m) return "";
    return m[1].replace(/<[^>]+>/g, "").trim();
}

const refId = extractText(html, /<p class="subHeader">\s*(.*?)\s*<\/p>/);
const url = extractText(html, /<link rel="canonical" href="([^"]+)"/);

let title = extractText(html, /<h1[^>]*>\s*([\s\S]*?)\s*<\/h1>/);
title = title.replace(/<[^>]+>/g, "").trim();

const priceRaw = extractText(html, /<h2 class="h3">\s*([\s\S]*?)\s*<span class="price-for-m2"/);
const price = parseNumber(priceRaw.replace(/<[^>]+>/g, "").replace(/PLN|zł/gi, ""));

const ppm2Raw = extractText(html, /class="price-for-m2"[^>]*>([\s\S]*?)<\/span>/);
const pricePerM2 = parseNumber(ppm2Raw.replace(/<[^>]+>/g, "").replace(/zł za m2?/gi, ""));

const areaRaw = extractSpec(html, "Powierzchnia");
const area = parseNumber(areaRaw.replace(/m2?/gi, ""));

const roomsRaw = extractSpec(html, "Ilość pokoi");
const rooms = parseNumber(roomsRaw) || 0;

return [{
    json: {
        external_id: "TS-" + (refId ? refId.replace(/\//g, "-") : Date.now()),
        category: "mieszkanie-krakow",
        url: url,
        title: "Oferta TS: " + (title || refId),
        price: price,
        price_per_m2: pricePerM2,
        area: area,
        rooms: rooms,
        lot_size: 0,
        construction_year: 0,
        created_at: new Date().toISOString(),
        property_portal: 'Tecnocasa',
        raw_html: html
    }
}];

const items = $input.all();
const html = items[0].json.data || "";

const jsonMatch = html.match(/<script\b[^>]*type="application\/json"[^>]*>([\s\S]*?pageProps[\s\S]*?)<\/script>/);

if (!jsonMatch) {
    return [{ json: { error: "Failed to extract JSON with offers" } }];
}

try {
    const fullData = JSON.parse(jsonMatch[1].trim());
    const ads = fullData?.props?.pageProps?.data?.searchAds?.items || 
                fullData?.props?.pageProps?.apolloState?.data?.searchAds?.items || [];

    if (ads.length === 0) return [];

    return ads.map(ad => ({
        json: {
            external_id: "OT-" + ad.id,
            category: "mieszkanie-krakow",
            url: "https://www.otodom.pl/pl/oferta/" + ad.slug,
            title: "Oferta OT: " + ad.title,
            price: ad.totalPrice?.value || 0,
            price_per_m2: ad.pricePerSquareMeter?.value || 0,
            area: ad.areaInSquareMeters || 0,
            rooms: ad.roomsNumber || 0,
            lot_size: 0,
            construction_year: 0,
            created_at: new Date().toISOString(),
            property_portal: 'Otodom'          
        }
    }));

} catch (e) {
    return [{ json: { error: "JSON parsing error: " + e.message } }];
}

const items = $input.all();

const MIN_AREA_SQM = 90;

const isNonEmpty = (value) => String(value ?? '').trim() !== '';
const isUndefinedLiteral = (value) => String(value ?? '').trim().toLowerCase() === 'undefined';
const isHttpUrl = (value) => /^https?:\/\//i.test(String(value ?? '').trim());

return items
  .map((item) => ({ ...item, json: { ...item.json } }))
  .filter((item) => {
    const externalId = item.json.external_id;
    const url = item.json.url;

    if (!isNonEmpty(externalId) || isUndefinedLiteral(externalId)) return false;
    if (!isNonEmpty(url) || isUndefinedLiteral(url)) return false;
    if (!isHttpUrl(url)) return false;

    // Reject offers below minimum area when area is known
    const area = Number(item.json.area);
    if (area > 0 && area < MIN_AREA_SQM) return false;

    return true;
  });

