const raw = String($json.output || '').trim();

const parseNumber = (value, fallback = 0) => {
  const normalized = String(value ?? '').trim();
  if (!normalized) return fallback;

  const num = Number(normalized.replace(',', '.'));
  return Number.isFinite(num) ? num : fallback;
};

const parseNullableNumber = (value) => {
  const normalized = String(value ?? '').trim();
  if (!normalized) return null;

  const num = Number(normalized.replace(',', '.'));
  return Number.isFinite(num) ? num : null;
};

const stripFences = (text) => {
  const trimmed = String(text || '').trim();
  const fenceMatch = trimmed.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  return fenceMatch ? fenceMatch[1].trim() : trimmed;
};

const escapeHtml = (text) =>
  String(text || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');

const inferExternalIdFromRaw = (text) => {
  const source = stripFences(text);
  const match = source.match(/"external_id"\s*:\s*"([^"]+)"/i);
  return String(match?.[1] || '').trim();
};

const inferAiRatingFromRaw = (text) => {
  const source = stripFences(text);
  const match = source.match(/"ai_rating"\s*:\s*([0-9]{1,2})/i);
  return match ? Number(match[1]) : null;
};

const inferAiAnalysisHtmlFromRaw = (text) => {
  const source = stripFences(text);
  const marker = '"ai_analysis_html"';
  const markerIndex = source.toLowerCase().indexOf(marker.toLowerCase());
  if (markerIndex === -1) return '';

  const afterMarker = source.slice(markerIndex);
  const firstQuote = afterMarker.indexOf('"', marker.length);
  if (firstQuote === -1) return '';

  const valuePart = afterMarker.slice(firstQuote + 1);
  const endQuoteMatch = valuePart.match(/"\s*(,|\})/);
  const quoted = endQuoteMatch ? valuePart.slice(0, endQuoteMatch.index) : valuePart;

  const normalized = quoted
    .replace(/\\n/g, '\n')
    .replace(/\\r/g, '\r')
    .replace(/\\t/g, '\t')
    .replace(/\\"/g, '"')
    .replace(/\\\//g, '/');

  return String(normalized || '').trim();
};

const buildCurrentParsed = () => {
  const currentAiRating = parseNullableNumber($json.ai_rating);
  const rawExternalId = inferExternalIdFromRaw(raw);

  return {
    external_id: String($json.external_id || rawExternalId || '').trim(),
    title: String($json.title || '').trim(),
    price: parseNumber($json.price, 0),
    price_per_m2: parseNumber($json.price_per_m2, 0),
    area: parseNumber($json.area, 0),
    lot_size: parseNumber($json.lot_size, 0),
    construction_year: Math.round(parseNumber($json.construction_year, 0)),
    ai_rating: currentAiRating === null ? null : Math.round(currentAiRating),
    ai_analysis_html: String($json.ai_analysis_html || '').trim(),
  };
};

const buildFailure = (reason, details = {}) => ([{
  json: {
    ...$json,
    ai_parse_valid: false,
    ai_parse_error: reason,
    ai_parse_details: details,
    ai_parsed: buildCurrentParsed(),
  },
}]);

if (!raw) {
  return buildFailure('empty_output');
}

const parseJson = (text) => {
  const candidate = stripFences(text);

  try {
    return JSON.parse(candidate);
  } catch (_) {
    const objectMatch = candidate.match(/\{[\s\S]*\}/);
    if (!objectMatch) return null;

    try {
      return JSON.parse(objectMatch[0]);
    } catch (_) {
      return null;
    }
  }
};

const expectedExternalId = String($json.external_id || '').trim();
const parsed = parseJson(raw);

let parsedExternalId = '';
let parsedTitle = '';
let parsedPrice = parseNumber($json.price, 0);
let parsedPricePerM2 = parseNumber($json.price_per_m2, 0);
let parsedArea = parseNumber($json.area, 0);
let parsedLotSize = parseNumber($json.lot_size, 0);
let parsedConstructionYear = Math.round(parseNumber($json.construction_year, 0));
let aiRating = parseNullableNumber($json.ai_rating);
let aiAnalysisHtml = String($json.ai_analysis_html || '').trim();
let parseError = null;
let parseDetails = null;

if (parsed && typeof parsed === 'object') {
  parsedExternalId = String(parsed.external_id || '').trim();
  parsedTitle = String(parsed.title || '').trim();
  parsedPrice = parseNumber(parsed.price, parsedPrice);
  parsedPricePerM2 = parseNumber(parsed.price_per_m2, parsedPricePerM2);
  parsedArea = parseNumber(parsed.area, parsedArea);
  parsedLotSize = parseNumber(parsed.lot_size, parsedLotSize);
  parsedConstructionYear = Math.round(parseNumber(parsed.construction_year, parsedConstructionYear));
  aiRating = parseNullableNumber(parsed.ai_rating);
  aiAnalysisHtml = String(parsed.ai_analysis_html || aiAnalysisHtml).trim();
} else {
  parsedExternalId = inferExternalIdFromRaw(raw);
  parsedTitle = String($json.title || '').trim();
  const recoveredRating = inferAiRatingFromRaw(raw);
  aiRating = Number.isFinite(recoveredRating) ? recoveredRating : aiRating;
  aiAnalysisHtml = inferAiAnalysisHtmlFromRaw(raw) || aiAnalysisHtml;

  parseError = 'invalid_json_recovered';
  parseDetails = {
    recovered_external_id: parsedExternalId || null,
    recovered_ai_rating: Number.isFinite(aiRating) ? aiRating : null,
  };
}

if (!parsedExternalId) {
  parsedExternalId = expectedExternalId;
}

if (!parsedExternalId) {
  return buildFailure('missing_external_id');
}

if (expectedExternalId && parsedExternalId !== expectedExternalId) {
  return buildFailure('external_id_mismatch', {
    expected_external_id: expectedExternalId,
    parsed_external_id: parsedExternalId,
  });
}

const roundedRating = aiRating === null ? null : Math.round(parseNumber(aiRating, NaN));
if (!Number.isFinite(roundedRating) || roundedRating < 1 || roundedRating > 10) {
  return buildFailure('invalid_ai_rating', {
    parsed_ai_rating: aiRating,
  });
}

if (!aiAnalysisHtml) {
  const fallbackPreview = stripFences(raw).slice(0, 3500);
  aiAnalysisHtml = `<pre>${escapeHtml(fallbackPreview)}</pre>`;
  if (!parseError) {
    parseError = 'missing_ai_analysis_html_recovered';
    parseDetails = { recovered_from_raw_preview: true };
  }
}

return [{
  json: {
    ...$json,
    ai_parse_valid: parseError ? false : true,
    ai_parse_error: parseError,
    ai_parse_details: parseDetails,
    ai_parsed: {
      external_id: parsedExternalId,
      title: parsedTitle || String($json.title || '').trim() || 'Oferta: ' + parsedExternalId,
      price: parsedPrice,
      price_per_m2: parsedPricePerM2,
      area: parsedArea,
      lot_size: parsedLotSize,
      construction_year: parsedConstructionYear,
      ai_rating: roundedRating,
      ai_analysis_html: aiAnalysisHtml,
    },
  },
}];

const feedbackHint = $json.feedback_hint || 'No feedback hint available';

const getPairedOffer = (nodeName) => {
  try {
    const candidate = $(nodeName).item?.json;
    return candidate && candidate.external_id ? candidate : null;
  } catch (error) {
    return null;
  }
};

const offer =
  getPairedOffer('Wait') ||
  getPairedOffer('Loop Over Items') ||
  getPairedOffer('Code in JavaScript - merge backfill with desc') ||
  getPairedOffer('Code in JavaScript - merge offer with desc') ||
  {};

return [{
  json: {
    ...offer,
    feedback_hint: feedbackHint,
    feedback_hint_debug: feedbackHint
  }
}];
